import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../api/axiosConfig';
import toast from 'react-hot-toast';
import { UserPlus, User, Mail, Lock } from 'lucide-react';

const RegisterPage = () => {
  const [data, setData] = useState({ fullName: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    const toastId = toast.loading('INITIALIZING_IDENTITY_NODE...');
    setLoading(true);
    try {
      await api.post('/auth/register', data);
      toast.success('IDENTITY_INITIALIZED', { id: toastId });
      navigate('/login');
    } catch (err) {
      toast.error('REGISTRATION_FAILED', { id: toastId });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="w-full flex justify-center reveal-data">
      <div className="terminal-card shadow-2xl overflow-hidden">
        
        <div className="absolute top-0 left-0 w-full h-[1px] bg-emerald-500/40 shadow-[0_0_15px_var(--accent-glow)] animate-scan" />

        <div className="text-center mb-10">
          <div className="flex justify-center mb-6 text-emerald-500">
            <UserPlus size={42} />
          </div>
          <h1 className="text-2xl font-bold tracking-[0.3em] text-white uppercase">
            Initialize_Node
          </h1>
          <p className="text-[10px] text-white/30 uppercase tracking-[0.25em] font-mono mt-2">
            Identity Setup // System_V3.0_Core
          </p>
        </div>

        <form onSubmit={handleRegister} className="space-y-4">
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-[10px] text-emerald-500 font-bold uppercase tracking-widest ml-1">
              <User size={12} /> Full_Identity
            </label>
            <input
              type="text"
              className="terminal-input"
              placeholder="Operator Name"
              onChange={(e) => setData({ ...data, fullName: e.target.value })}
              required
            />
          </div>

          <div className="space-y-2">
            <label className="flex items-center gap-2 text-[10px] text-emerald-500 font-bold uppercase tracking-widest ml-1">
              <Mail size={12} /> Registry_Email
            </label>
            <input
              type="email"
              className="terminal-input"
              placeholder="operator@finify.ai"
              onChange={(e) => setData({ ...data, email: e.target.value })}
              required
            />
          </div>

          <div className="space-y-2">
            <label className="flex items-center gap-2 text-[10px] text-emerald-500 font-bold uppercase tracking-widest ml-1">
              <Lock size={12} /> Security_Key
            </label>
            <input
              type="password"
              className="terminal-input"
              placeholder="••••••••"
              onChange={(e) => setData({ ...data, password: e.target.value })}
              required
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="emerald-btn mt-6"
          >
            {loading ? 'INITIALIZING...' : 'Initialize_Identity_Node'}
          </button>
        </form>

        <div className="mt-8 pt-6 border-t border-white/5 text-center">
          <p className="text-[10px] text-white/30 uppercase tracking-[0.25em]">
            Identity exists?{' '}
            <Link to="/login" className="text-emerald-500 underline hover:text-emerald-400 transition-colors">
              Access_Gate
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default RegisterPage;
